fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut vec = Vec::new();
    vec.push(Box::new(MyStruct));

    for item in vec.iter_mut() {
        item.do_something()?;
    }
    Ok(())
}

struct MyStruct;

trait MyTrait {
    fn do_something(&self) -> Result<(), Box<dyn std::error::Error>>;
}

impl MyTrait for MyStruct {
    fn do_something(&self) -> Result<(), Box<dyn std::error::Error>> {
        // Simulate an error
        Err("Something went wrong".into())
    }
